void doubleAll(int arr[], int size) {
    for (int i = 0; i < size; i++) {
        arr[i] *= 2;
    }
}

int main() {
    int nums[3] = {1, 2, 3};
    doubleAll(nums, 3);
    printf("%d%d%d", nums[0], nums[1], nums[2]);
    return 0;
}
